@code {
    private AppointmentModel Model { get; set; } = new();
    private EditContext editContext = default!;

    private bool showStep2;
    private bool availabilityChecked;
    private bool submitted;
    private string? dateError;

    private List<string> doctors = [];
    private List<string> timeSlots = [];
    private Dictionary<string, string> serverErrors = new();

    // Fields that belong to step 1 for partial validation
    private static readonly string[] Step1Fields =
        [nameof(AppointmentModel.PatientName), nameof(AppointmentModel.Email),
         nameof(AppointmentModel.Phone), nameof(AppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields
        editContext = new EditContext(Model);
        var isValid = editContext.Validate();

        // Check if any step-1 field has errors
        if (Step1Fields.All(f =>
                !editContext.GetValidationMessages(editContext.Field(f)).Any()))
        {
            // Also make sure step-1 fields are actually filled
            if (!string.IsNullOrWhiteSpace(Model.PatientName) &&
                !string.IsNullOrWhiteSpace(Model.Email) &&
                !string.IsNullOrWhiteSpace(Model.Phone) &&
                !string.IsNullOrWhiteSpace(Model.InsuranceProvider))
            {
                showStep2 = true;
            }
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
        serverErrors.Clear();
    }

    private async Task OnDateChanged()
    {
        dateError = null;
        timeSlots.Clear();
        Model.TimeSlot = "";
        availabilityChecked = false;
        serverErrors.Clear();

        if (Model.AppointmentDate is { } d)
        {
            if (d <= DateOnly.FromDateTime(DateTime.Today))
            {
                dateError = "Date must be in the future.";
                return;
            }

            if (!string.IsNullOrEmpty(Model.Doctor))
            {
                timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(Model.Doctor, d);
            }
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;
        dateError = null;

        // Re-validate the full form via DataAnnotations
        editContext = new EditContext(Model);
        if (!editContext.Validate())
        {
            return;
        }

        // Custom date-in-future check
        if (Model.AppointmentDate is null || Model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            dateError = "Date must be in the future.";
            return;
        }

        // Server-side business rules
        var errors = await AppointmentSvc.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
            return;
        }

        availabilityChecked = true;
    }

    private async Task HandleSubmit()
    {
        if (!availabilityChecked)
        {
            return;
        }

        // Run server validation once more before final submission
        serverErrors.Clear();
        var errors = await AppointmentSvc.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
            availabilityChecked = false;
            return;
        }

        submitted = true;
    }
}

